 useEffect(()=>{const timer=setTimeout(()=>{api<any[]>(`/api/agents/character-creator/cosmetics?kind=skin&gender=${newChar.gender}&q=${encodeURIComponent(skinQ)}&limit=50`).then(setSkinOptions).catch(()=>setSkinOptions([]))},160);return()=>clearTimeout(timer)},[newChar.gender,skinQ]);
