 useEffect(()=>{const timer=setTimeout(()=>{api<any[]>(`/api/agents/character-creator/cosmetics?kind=bottom&gender=${newChar.gender}&q=${encodeURIComponent(bottomQ)}&limit=50`).then(rows=>setBottomOptions(rows.length?rows:[fallbackOption("Bottom",newChar.bottom)].filter(Boolean))).catch(()=>setBottomOptions([fallbackOption("Bottom",newChar.bottom)].filter(Boolean)))},160);return()=>clearTimeout(timer)},[newChar.gender,bottomQ,newChar.bottom]);
 useEffect(()=>{const timer=setTimeout(()=>{api<any[]>(`/api/agents/character-creator/cosmetics?kind=shoes&gender=${newChar.gender}&q=${encodeURIComponent(shoesQ)}&limit=50`).then(rows=>setShoesOptions(rows.length?rows:[fallbackOption("Shoes",newChar.shoes)].filter(Boolean))).catch(()=>setShoesOptions([fallbackOption("Shoes",newChar.shoes)].filter(Boolean)))},160);return()=>clearTimeout(timer)},[newChar.gender,shoesQ,newChar.shoes]);
 useEffect(()=>{const timer=setTimeout(()=>{api<any[]>(`/api/agents/character-creator/cosmetics?kind=weapon&gender=${newChar.gender}&q=${encodeURIComponent(weaponQ)}&limit=50`).then(rows=>setWeaponOptions(rows.length?rows:[fallbackOption("Weapon",newChar.weapon)].filter(Boolean))).catch(()=>setWeaponOptions([fallbackOption("Weapon",newChar.weapon)].filter(Boolean)))},160);return()=>clearTimeout(timer)},[newChar.gender,weaponQ,newChar.weapon]);
