const cardSlotGroups=[
 {title:"Default behavior cards",sub:"Top-row fallback behaviors used when no schedule, queue, active task, or script is steering the agent.",slots:["default_behavior_1","default_behavior_2","default_behavior_3"],types:["BEHAVIOR"],kind:"default"},
 {title:"Default active task and overrides",sub:"Direct active task is the fallback task layer. Schedule and queue tasks override it while active; task override behaviors apply only while some task is controlling the agent.",slots:["active_task","task_override_behavior_1","task_override_behavior_2","task_override_behavior_3"],primarySlots:["active_task"],secondaryTitle:"Task override behavior cards",secondarySub:"These behavior cards are considered only when a schedule, queue, direct active task, or default task pool is currently selected.",secondarySlots:["task_override_behavior_1","task_override_behavior_2","task_override_behavior_3"],typesBySlot:{active_task:["TASK"],task_override_behavior_1:["BEHAVIOR"],task_override_behavior_2:["BEHAVIOR"],task_override_behavior_3:["BEHAVIOR"]},kind:"task"},
 {title:"Personality cards",sub:"Dialogue, facial expression, and social style hooks. Expressive personalities can use F3/F7 and playful idle actions.",slots:["personality_1","personality_2","personality_3"],types:["PERSONALITY"],kind:"identity"},
 {title:"Safety and passive cards",sub:"Always-on constraints, utility preferences, and non-conflicting passive behavior.",slots:["safety_1","passive_1","passive_2"],types:["POLICY","UTILITY","BEHAVIOR","PERSONALITY"],kind:"passive"}
];
function cardLabel(card:any){return card?`${card.name} (${card.card_key})`:"Empty slot"}
function Cards(){
 const [agents,setAgents]=useState<any[]>([]),[cards,setCards]=useState<any[]>([]),[selected,setSelected]=useState<any|null>(null),[loadout,setLoadout]=useState<any[]>([]),[taskStack,setTaskStack]=useState<any>({queue:[],schedules:[],defaults:[]}),[q,setQ]=useState(""),[type,setType]=useState(""),[reason,setReason]=useState("Updated agent card loadout through Agent CMS"),[error,setError]=useState("");
 const [queueDraft,setQueueDraft]=useState<any>({cardId:"",queueOrder:0,status:"PENDING",runMode:"FINITE",repeatPolicy:"ONCE",parameterJson:"",notes:""});
 const [scheduleDraft,setScheduleDraft]=useState<any>({cardId:"",scheduleName:"",daysOfWeek:"ALL",startTime:"",endTime:"",priority:0,runMode:"REUSABLE",repeatPolicy:"LOOP",parameterJson:"",notes:""});
 const [defaultDraft,setDefaultDraft]=useState<any>({cardId:"",priority:0,selectionRule:"PRIORITY",runMode:"REUSABLE",repeatPolicy:"LOOP",parameterJson:"",notes:""});
 const [expandedConfigId,setExpandedConfigId]=useState<any|null>(null);
 const loadAgents=()=>api<any[]>(`/api/agents?q=${encodeURIComponent(q)}`).then(rows=>{setAgents(rows);if(!selected&&rows.length)setSelected(rows[0]);if(selected){const next=rows.find(row=>row.id===selected.id);if(next)setSelected(next)}}).catch(x=>setError((x as Error).message));
 const loadCards=()=>api<any[]>(`/api/agents/cards?q=${encodeURIComponent(q)}&type=${encodeURIComponent(type)}`).then(setCards).catch(x=>setError((x as Error).message));
 const loadLoadout=(agent:any)=>agent?api<any>(`/api/agents/${agent.id}/card-loadout`).then(row=>setLoadout(row.loadout||[])).catch(x=>setError((x as Error).message)):setLoadout([]);
 const loadTaskStack=(agent:any)=>agent?api<any>(`/api/agents/${agent.id}/task-stack`).then(row=>setTaskStack(row)).catch(x=>setError((x as Error).message)):setTaskStack({queue:[],schedules:[],defaults:[]});
 useEffect(()=>{const timer=setTimeout(()=>{loadAgents();loadCards()},160);return()=>clearTimeout(timer)},[q,type]);
 useEffect(()=>{loadLoadout(selected);loadTaskStack(selected)},[selected?.id]);
 const slotRow=(slot:string)=>loadout.find(row=>row.slot_key===slot);
 const compatible=(types:string[])=>cards.filter(card=>types.includes(card.card_type));
 const slotTypes=(group:any,slot:string)=>group.typesBySlot?.[slot]||group.types||[];
 const duplicateScope=(slot:string)=>slot.replace(/_\d+$/,"");
 const optionsForSlot=(group:any,slot:string)=>{
  const current=slotRow(slot);
  const used=new Set(group.slots.filter((other:string)=>other!==slot&&duplicateScope(other)===duplicateScope(slot)).map((other:string)=>String(slotRow(other)?.card_id||"")).filter(Boolean));
  return compatible(slotTypes(group,slot)).filter(card=>String(current?.card_id||"")===String(card.id)||!used.has(String(card.id)));
 };
 const renderCardSlot=(group:any,slot:string)=>{const row=slotRow(slot),options=optionsForSlot(group,slot);return <article className="card-slot" key={slot}><code>{slot}</code><select className="edit" value={row?.card_id||""} onChange={e=>saveSlot(slot,e.target.value)}><option value="">Empty slot</option>{options.map(card=><option value={card.id} key={card.id}>{cardLabel(card)}</option>)}</select>{row?<><strong>{row.name}</strong><small>{row.card_key} | {row.card_type}</small><p>{row.description}</p><button className="secondary clear-action" onClick={()=>clearSlot(slot)}>Clear slot</button></>:<p className="muted">Pick a compatible card from the dropdown.</p>}</article>};
 async function saveSlot(slot:string,cardId:any){if(!selected||!cardId)return;setError("");try{const updated=await api<any>(`/api/agents/${selected.id}/card-loadout/${encodeURIComponent(slot)}`,{method:"PUT",body:JSON.stringify({cardId:Number(cardId),enabled:true,priority:0,reason})});setLoadout(updated.loadout||[])}catch(x){setError((x as Error).message)}}
 async function clearSlot(slot:string){if(!selected)return;setError("");try{const updated=await api<any>(`/api/agents/${selected.id}/card-loadout/${encodeURIComponent(slot)}?reason=${encodeURIComponent(reason)}`,{method:"DELETE"});setLoadout(updated.loadout||[])}catch(x){setError((x as Error).message)}}
 async function addQueueTask(){if(!selected||!queueDraft.cardId)return;setError("");try{const row=await api<any>(`/api/agents/${selected.id}/task-queue`,{method:"POST",body:JSON.stringify({...queueDraft,cardId:Number(queueDraft.cardId),queueOrder:Number(queueDraft.queueOrder||0),reason})});setTaskStack(row)}catch(x){setError((x as Error).message)}}
 async function deleteQueueTask(row:any){if(!selected)return;setError("");try{setTaskStack(await api<any>(`/api/agents/${selected.id}/task-queue/${row.id}?reason=${encodeURIComponent(reason)}`,{method:"DELETE"}))}catch(x){setError((x as Error).message)}}
 async function addSchedule(){if(!selected||!scheduleDraft.cardId)return;setError("");try{const body={...scheduleDraft,cardId:Number(scheduleDraft.cardId),priority:Number(scheduleDraft.priority||0),startTime:scheduleDraft.startTime||null,endTime:scheduleDraft.endTime||null,reason};setTaskStack(await api<any>(`/api/agents/${selected.id}/task-schedules`,{method:"POST",body:JSON.stringify(body)}))}catch(x){setError((x as Error).message)}}
 async function deleteSchedule(row:any){if(!selected)return;setError("");try{setTaskStack(await api<any>(`/api/agents/${selected.id}/task-schedules/${row.id}?reason=${encodeURIComponent(reason)}`,{method:"DELETE"}))}catch(x){setError((x as Error).message)}}
 async function addDefaultTask(){if(!selected||!defaultDraft.cardId)return;setError("");try{const body={...defaultDraft,cardId:Number(defaultDraft.cardId),priority:Number(defaultDraft.priority||0),reason};setTaskStack(await api<any>(`/api/agents/${selected.id}/task-defaults`,{method:"POST",body:JSON.stringify(body)}))}catch(x){setError((x as Error).message)}}
 async function deleteDefaultTask(row:any){if(!selected)return;setError("");try{setTaskStack(await api<any>(`/api/agents/${selected.id}/task-defaults/${row.id}?reason=${encodeURIComponent(reason)}`,{method:"DELETE"}))}catch(x){setError((x as Error).message)}}
 const taskCards=cards.filter(card=>card.card_type==="TASK");
 return <><article className="panel intro"><Title title="Agent card loadouts" sub="Equip task, behavior, and personality cards per agent. Active goals and scripts still win; cards define the fallback identity and future task-card layers."/></article>
  <PageToolbar query={q} onQueryChange={setQ} placeholder="Search agent, card, type, or purpose"/>
  <div className="filters compact"><select value={type} onChange={e=>setType(e.target.value)}><option value="">All card types</option><option value="TASK">Task</option><option value="BEHAVIOR">Behavior</option><option value="PERSONALITY">Personality</option><option value="POLICY">Policy</option><option value="UTILITY">Utility</option></select><label><small className="muted">Audit reason</small><input className="edit" value={reason} onChange={e=>setReason(e.target.value)}/></label></div>
  {error&&<div className="error">{error}</div>}
  <div className="agent-detail cards-layout">
   <section className="panel"><Title title="Choose agent" sub={`${agents.length} matching agents`}/>
    <div className="agent-list">{agents.map(agent=><button className={selected?.id===agent.id?"selected":""} key={agent.id} onClick={()=>setSelected(agent)}><AgentAvatar agent={agent}/><span className="agent-name-block"><strong>{agent.display_name||agent.character_name}</strong><small>{agent.account_name} {"->"} {agent.character_name} | Lv. {agent.level} | World {agent.world}</small></span></button>)}</div>
    {!agents.length&&<p className="muted">No agents match this search.</p>}
   </section>
    <section className="panel"><Title title={selected?`${selected.display_name||selected.character_name}'s cards`:"Card loadout"} sub="Default behavior applies only when no stronger task layer is active. Queue and schedule override the direct default active-task slot."/>
     {!selected?<p className="muted">Choose an agent first.</p>:<><div className="selected-agent-summary"><AgentAvatar agent={selected}/><div><strong>{selected.display_name||selected.character_name}</strong><small>{selected.account_name} {"->"} {selected.character_name} | Lv. {selected.level} | World {selected.world}</small></div></div>{cardSlotGroups.map(group=><div className={`card-slot-group ${group.kind||""}`} key={group.title}><div><strong>{group.title}</strong><p>{group.sub}</p></div>{group.primarySlots?<><div className="card-slot-row active-task-row">{group.primarySlots.map((slot:string)=>renderCardSlot(group,slot))}</div><div className="card-slot-subhead"><strong>{group.secondaryTitle}</strong><p>{group.secondarySub}</p></div><div className="card-slot-grid">{group.secondarySlots.map((slot:string)=>renderCardSlot(group,slot))}</div></>:<div className="card-slot-grid">{group.slots.map((slot:string)=>renderCardSlot(group,slot))}</div>}</div>)}</>}
   </section>
  </div>
  {selected&&<section className="panel"><Title title="Active task queue and scheduling" sub="Selection order: current schedule, queued active/pending task, direct active-task slot, default task pool, then behavior fallback."/>
   <div className="card-task-grid">
    <article className="card-task-panel"><strong>Queue active task cards</strong><p className="muted">Finite cards can be marked completed later and skipped forever. Reusable cards can loop or be requeued.</p><select className="edit" value={queueDraft.cardId} onChange={e=>setQueueDraft({...queueDraft,cardId:e.target.value})}><option value="">Choose task card</option>{taskCards.map(card=><option value={card.id} key={card.id}>{cardLabel(card)}</option>)}</select><div className="behavior-fields"><label><small>Order</small><input className="edit" type="number" value={queueDraft.queueOrder} onChange={e=>setQueueDraft({...queueDraft,queueOrder:e.target.value})}/></label><label><small>Status</small><select className="edit" value={queueDraft.status} onChange={e=>setQueueDraft({...queueDraft,status:e.target.value})}><option>PENDING</option><option>ACTIVE</option><option>COMPLETED</option><option>SKIPPED</option></select></label><label><small>Run mode</small><select className="edit" value={queueDraft.runMode} onChange={e=>setQueueDraft({...queueDraft,runMode:e.target.value})}><option>FINITE</option><option>REUSABLE</option></select></label><label><small>Repeat</small><select className="edit" value={queueDraft.repeatPolicy} onChange={e=>setQueueDraft({...queueDraft,repeatPolicy:e.target.value})}><option>ONCE</option><option>LOOP</option><option>REQUEUE</option></select></label></div><textarea className="edit parameter-json" value={queueDraft.parameterJson} onChange={e=>setQueueDraft({...queueDraft,parameterJson:e.target.value})} placeholder='Parameter JSON, e.g. {"targetLevel":15,"durationMinutes":30,"collectItemId":4000016,"quantity":30}'/><input className="edit" value={queueDraft.notes} onChange={e=>setQueueDraft({...queueDraft,notes:e.target.value})} placeholder="notes"/><button className="primary" onClick={addQueueTask}>Add queued task</button>{(taskStack.queue||[]).map((row:any)=><div className="task-row" key={row.id}><div><strong>{row.name}</strong><small>{row.status} | order {row.queue_order} | {row.run_mode}/{row.repeat_policy}</small>{row.parameter_json&&<small>params {row.parameter_json}</small>}</div><button className="secondary" onClick={()=>deleteQueueTask(row)}>Remove</button></div>)}</article>
    <article className="card-task-panel"><strong>Schedule active task cards</strong><p className="muted">Use 24-hour local time. Days can be ALL or comma-separated MON,TUE,WED,THU,FRI,SAT,SUN.</p><select className="edit" value={scheduleDraft.cardId} onChange={e=>setScheduleDraft({...scheduleDraft,cardId:e.target.value})}><option value="">Choose task card</option>{taskCards.map(card=><option value={card.id} key={card.id}>{cardLabel(card)}</option>)}</select><input className="edit" value={scheduleDraft.scheduleName} onChange={e=>setScheduleDraft({...scheduleDraft,scheduleName:e.target.value})} placeholder="Schedule name"/><div className="behavior-fields"><label><small>Days</small><input className="edit" value={scheduleDraft.daysOfWeek} onChange={e=>setScheduleDraft({...scheduleDraft,daysOfWeek:e.target.value.toUpperCase()})}/></label><label><small>Start</small><input className="edit" type="time" value={scheduleDraft.startTime} onChange={e=>setScheduleDraft({...scheduleDraft,startTime:e.target.value})}/></label><label><small>End</small><input className="edit" type="time" value={scheduleDraft.endTime} onChange={e=>setScheduleDraft({...scheduleDraft,endTime:e.target.value})}/></label><label><small>Priority</small><input className="edit" type="number" value={scheduleDraft.priority} onChange={e=>setScheduleDraft({...scheduleDraft,priority:e.target.value})}/></label><label><small>Run mode</small><select className="edit" value={scheduleDraft.runMode} onChange={e=>setScheduleDraft({...scheduleDraft,runMode:e.target.value})}><option>FINITE</option><option>REUSABLE</option></select></label><label><small>Repeat</small><select className="edit" value={scheduleDraft.repeatPolicy} onChange={e=>setScheduleDraft({...scheduleDraft,repeatPolicy:e.target.value})}><option>ONCE</option><option>LOOP</option><option>REQUEUE</option></select></label></div><textarea className="edit parameter-json" value={scheduleDraft.parameterJson} onChange={e=>setScheduleDraft({...scheduleDraft,parameterJson:e.target.value})} placeholder='Parameter JSON, e.g. {"mapId":100000000,"durationMinutes":60}'/><button className="primary" onClick={addSchedule}>Add schedule</button>{(taskStack.schedules||[]).map((row:any)=><div className="task-row" key={row.id}><div><strong>{row.schedule_name}: {row.name}</strong><small>{row.days_of_week} {row.start_time||"any"}-{row.end_time||"any"} | priority {row.priority} | {row.run_mode}/{row.repeat_policy}</small>{row.parameter_json&&<small>params {row.parameter_json}</small>}</div><button className="secondary" onClick={()=>deleteSchedule(row)}>Remove</button></div>)}</article>
    <article className="card-task-panel"><strong>Default task pool</strong><p className="muted">Used when no schedule, queue, or direct active task is available. Priority is deterministic; random gives variety.</p><select className="edit" value={defaultDraft.cardId} onChange={e=>setDefaultDraft({...defaultDraft,cardId:e.target.value})}><option value="">Choose task card</option>{taskCards.map(card=><option value={card.id} key={card.id}>{cardLabel(card)}</option>)}</select><div className="behavior-fields"><label><small>Priority</small><input className="edit" type="number" value={defaultDraft.priority} onChange={e=>setDefaultDraft({...defaultDraft,priority:e.target.value})}/></label><label><small>Selection</small><select className="edit" value={defaultDraft.selectionRule} onChange={e=>setDefaultDraft({...defaultDraft,selectionRule:e.target.value})}><option>PRIORITY</option><option>RANDOM</option><option>NEAREST</option></select></label><label><small>Run mode</small><select className="edit" value={defaultDraft.runMode} onChange={e=>setDefaultDraft({...defaultDraft,runMode:e.target.value})}><option>REUSABLE</option><option>FINITE</option></select></label><label><small>Repeat</small><select className="edit" value={defaultDraft.repeatPolicy} onChange={e=>setDefaultDraft({...defaultDraft,repeatPolicy:e.target.value})}><option>LOOP</option><option>ONCE</option><option>REQUEUE</option></select></label></div><textarea className="edit parameter-json" value={defaultDraft.parameterJson} onChange={e=>setDefaultDraft({...defaultDraft,parameterJson:e.target.value})} placeholder='Parameter JSON, e.g. {"selection":"nearest-safe-town","maxIdleMinutes":20}'/><input className="edit" value={defaultDraft.notes} onChange={e=>setDefaultDraft({...defaultDraft,notes:e.target.value})} placeholder="notes"/><button className="primary" onClick={addDefaultTask}>Add default task</button>{(taskStack.defaults||[]).map((row:any)=><div className="task-row" key={row.id}><div><strong>{row.name}</strong><small>{row.selection_rule} | priority {row.priority} | {row.run_mode}/{row.repeat_policy}</small>{row.parameter_json&&<small>params {row.parameter_json}</small>}</div><button className="secondary" onClick={()=>deleteDefaultTask(row)}>Remove</button></div>)}</article>
   </div>
  </section>}
  <section className="panel"><Title title="Card library" sub="Built-in cards are server-safe defaults. Custom card authoring can be added later without changing the loadout model."/>
   <div className="card-library-grid">{cards.flatMap(card=>[<article className="policy-card card-library-card" key={card.id}><div><strong>{card.name}</strong><code>{card.card_key}</code><p>{card.description}</p><small>{card.card_type} | priority {card.priority} | {card.built_in?"built-in":"custom"}</small></div><span className="active-state">{card.enabled?"Enabled":"Disabled"}</span>{card.config_json&&<button className="secondary config-toggle" onClick={()=>setExpandedConfigId(expandedConfigId===card.id?null:card.id)}>{expandedConfigId===card.id?"Hide config JSON":"Show config JSON"}</button>}</article>,expandedConfigId===card.id?<article className="config-row" key={`${card.id}-config`}><strong>{card.name} config JSON</strong><pre>{prettyJson(card.config_json)}</pre></article>:null])}</div>
   {!cards.length&&<p className="muted">No cards match this search.</p>}
  </section></>
}

function Runtime(){
 const [q,setQ]=useState(""),[sessions,setSessions]=useState<any[]>([]),[summary,setSummary]=useState<any|null>(null),[agents,setAgents]=useState<any[]>([]),[globalPolicies,setGlobalPolicies]=useState<any[]>([]),[globalCooldowns,setGlobalCooldowns]=useState<any[]>([]),[reason,setReason]=useState("Updated global agent defaults through Agent CMS"),[error,setError]=useState("");
 const loadGlobalDefaults=()=>{api<any[]>("/api/agents/policies/global").then(setGlobalPolicies).catch(()=>setGlobalPolicies([]));api<any[]>("/api/agents/cooldowns/global").then(setGlobalCooldowns).catch(()=>setGlobalCooldowns([]))};
 const loadAgents=()=>api<any[]>(`/api/agents?q=${encodeURIComponent(q)}`).then(setAgents).catch(x=>setError((x as Error).message));
 useEffect(()=>{const timer=setTimeout(()=>{api<any[]>(`/api/agents/runtime/sessions?q=${encodeURIComponent(q)}`).then(setSessions).catch(x=>setError((x as Error).message));loadAgents();api<any>("/api/agents/runtime/summary").then(setSummary).catch(()=>setSummary(null));loadGlobalDefaults()},160);return()=>clearTimeout(timer)},[q]);
 async function setGlobalPolicy(policy:any,enabled:boolean){setError("");try{await api<any>(`/api/agents/policies/global/${encodeURIComponent(policy.key)}`,{method:"PUT",body:JSON.stringify({enabled,reason})});loadGlobalDefaults()}catch(x){setError((x as Error).message)}}
 async function resetGlobalPolicy(policy:any){setError("");try{await api<any>(`/api/agents/policies/global/${encodeURIComponent(policy.key)}?reason=${encodeURIComponent(reason)}`,{method:"DELETE"});loadGlobalDefaults()}catch(x){setError((x as Error).message)}}
 async function setGlobalCooldown(cooldown:any,millis:any){setError("");const parsed=Number(millis);if(!Number.isFinite(parsed)||parsed<0){setError("Cooldown must be a non-negative number of milliseconds.");return}try{await api<any>(`/api/agents/cooldowns/global/${encodeURIComponent(cooldown.key)}`,{method:"PUT",body:JSON.stringify({millis:Math.round(parsed),reason})});loadGlobalDefaults()}catch(x){setError((x as Error).message)}}
 async function resetGlobalCooldown(cooldown:any){setError("");try{await api<any>(`/api/agents/cooldowns/global/${encodeURIComponent(cooldown.key)}?reason=${encodeURIComponent(reason)}`,{method:"DELETE"});loadGlobalDefaults()}catch(x){setError((x as Error).message)}}
 async function stopStaleSession(session:any){setError("");try{await api<any>(`/api/agents/runtime/sessions/${session.id}/mark-stale-stopped`,{method:"POST",body:JSON.stringify({reason})});api<any[]>(`/api/agents/runtime/sessions?q=${encodeURIComponent(q)}`).then(setSessions);api<any>("/api/agents/runtime/summary").then(setSummary).catch(()=>setSummary(null))}catch(x){setError((x as Error).message)}}
 const matches=(row:any,keys:string[])=>!q.trim()||keys.some(key=>String(row?.[key]??"").toLowerCase().includes(q.trim().toLowerCase()));
 const filteredPolicies=globalPolicies.filter(policy=>matches(policy,["label","key","description","globalValue"]));
 const filteredCooldowns=globalCooldowns.filter(cooldown=>matches(cooldown,["label","key","description","globalValue"]));
 const filteredProblems=problemsFilter(summary?.latestProblems||[],q);
 const filteredSafety=problemsFilter(summary?.latestSafety||[],q);
 const active=sessions.filter(row=>!row.ended_at).length;
 const sessionSummary=summary?.sessions||{},actionSummary=summary?.actions24h||{},safetySummary=summary?.safety24h||{},economySummary=summary?.economy24h||{};
 return <><article className="panel intro"><Title title="Runtime sessions" sub="Live and historical runtime shells. This is read-only observability for agent lifecycle state."/></article>
  <PageToolbar query={q} onQueryChange={setQ} placeholder="Search agent, character, state or task"/>
  <div className="metrics runtime-metrics"><article><RadioTower/><small>Open sessions</small><strong>{sessionSummary.open_sessions??active}</strong></article><article><Activity/><small>Stale sessions</small><strong>{sessionSummary.stale_sessions??0}</strong></article><article><Activity/><small>Blocked actions 24h</small><strong>{actionSummary.blocked_actions??0}</strong></article><article><Activity/><small>Failed actions 24h</small><strong>{actionSummary.failed_actions??0}</strong></article><article><Activity/><small>Cooldown blocks 24h</small><strong>{actionSummary.cooldown_blocks??0}</strong></article><article><Activity/><small>Safety warnings 24h</small><strong>{safetySummary.safety_warnings??0}</strong></article><article><Activity/><small>Shop buys 24h</small><strong>{economySummary.shop_buys??0}</strong></article><article><Coins/><small>Net meso 24h</small><strong>{Number(economySummary.net_meso_delta??0).toLocaleString()}</strong></article><article><Activity/><small>Matching sessions</small><strong>{sessions.length}</strong></article></div>
  {error&&<div className="error">{error}</div>}
  <div className="runtime-grid">
   <section className="panel runtime-defaults"><Title title="Global capability defaults" sub="Fallback capability gates used by every agent unless that agent has a per-character override."/>
    <label><small className="muted">Audit reason for global changes</small><textarea className="edit" value={reason} onChange={e=>setReason(e.target.value)} /></label>
    <div className="policy-grid">{filteredPolicies.map(policy=><article className="policy-card" key={policy.key}><div><strong>{policy.label}</strong><code>{policy.key}</code><p>{policy.description}</p><small>Built-in default {String(policy.defaultEnabled)} | Global row {policy.globalValue??"unset"}</small></div><span className={policy.effective?"active-state":"inactive-state"}>{policy.effective?"Allowed by default":"Blocked by default"}</span><div className="policy-actions"><button className="secondary" onClick={()=>setGlobalPolicy(policy,true)}>Allow</button><button className="secondary" onClick={()=>setGlobalPolicy(policy,false)}>Block</button><button className="secondary" disabled={!policy.overridden} onClick={()=>resetGlobalPolicy(policy)}>Use built-in</button></div></article>)}</div>
    {!filteredPolicies.length&&<p className="muted">No global capability defaults match this search.</p>}
   </section>
   <section className="panel runtime-defaults"><Title title="Global cooldown defaults" sub="Fallback pacing limits in milliseconds. Per-character cooldown overrides win over these values."/>
    <div className="policy-grid">{filteredCooldowns.map(cooldown=><article className="policy-card" key={cooldown.key}><div><strong>{cooldown.label}</strong><code>{cooldown.key}</code><p>{cooldown.description}</p><small>Built-in default {Number(cooldown.defaultMillis).toLocaleString()} ms | Global row {cooldown.globalValue??"unset"}</small></div><span className="active-state">{Number(cooldown.effectiveMillis).toLocaleString()} ms</span><div className="policy-actions"><input className="edit" key={`${cooldown.key}-${cooldown.effectiveMillis}-${cooldown.globalValue??"builtin"}`} type="number" min="0" max="3600000" defaultValue={cooldown.effectiveMillis} onKeyDown={e=>{if(e.key==="Enter")setGlobalCooldown(cooldown,(e.target as HTMLInputElement).value)}}/><button className="secondary" onClick={e=>setGlobalCooldown(cooldown,e.currentTarget.parentElement?.querySelector("input")?.value??cooldown.effectiveMillis)}>Save ms</button><button className="secondary" disabled={!cooldown.overridden} onClick={()=>resetGlobalCooldown(cooldown)}>Use built-in</button></div></article>)}</div>
    {!filteredCooldowns.length&&<p className="muted">No global cooldown defaults match this search.</p>}
   </section>
  </div>
  <section className="panel"><Title title="Latest blocked or failed actions" sub="Newest runtime problems across all agents."/>
   <div className="ledger-list">{filteredProblems.map((row:any)=><article className="ledger-card" key={row.id}>
    <div><strong>{row.display_name||row.character_name}</strong><small>{row.action_type} | {row.created_at}</small></div>
    <span className="inactive-state">{row.status}</span><p>{row.message}</p>
   </article>)}</div>{!filteredProblems.length&&<p className="muted">{q.trim()?"No matching blocked or failed actions.":"No blocked or failed actions recorded yet."}</p>}</section>
  <section className="panel"><Title title="Latest safety warnings" sub="Recent observational warnings from runtime ticks, including slow ticks, missing perception, detached references, and repeated blocks."/>
   <div className="ledger-list">{filteredSafety.map((row:any)=><article className="ledger-card" key={row.id}>
    <div><strong>{row.display_name||row.character_name}</strong><small>{row.event_type} | {row.created_at}</small></div>
    <span className="inactive-state">WATCH</span><p>{row.summary}</p>
    <div className="ledger-grid"><Tile label="Map" value={row.map_id??"unset"}/><Tile label="Importance" value={row.importance}/><Tile label="Character" value={row.character_name}/></div>
    {row.details_json&&<details><summary>Safety details</summary><pre>{row.details_json}</pre></details>}
   </article>)}</div>{!filteredSafety.length&&<p className="muted">{q.trim()?"No matching safety warnings.":"No safety warnings recorded yet."}</p>}</section>
  <section className="panel"><Title title="Session ledger" sub="Newest runtime sessions first."/>
   <div className="ledger-list">{sessions.map(session=><article className="ledger-card" key={session.id}>
    <div><strong>{session.display_name||session.character_name}</strong><small>{session.account_name} {"->"} {session.character_name}</small></div>
    <span className={Number(session.stale)===1||session.ended_at?"inactive-state":"active-state"}>{Number(session.stale)===1?"STALE":session.state}</span>
    <div className="ledger-grid"><Tile label="World" value={session.world}/><Tile label="Channel" value={session.channel}/><Tile label="Map" value={session.map_id}/><Tile label="Task" value={session.current_task||"none"}/><Tile label="Started" value={session.started_at}/><Tile label="Last tick" value={session.last_tick_at||"never"}/><Tile label="Seconds since tick" value={session.seconds_since_tick??"unset"}/><Tile label="Ended" value={session.ended_at||"open"}/><Tile label="Stop reason" value={session.stop_reason||"none"}/></div>
    {session.latest_safety_summary&&<div className="goal-diagnosis"><Activity size={18}/><div><strong>Latest safety warning</strong><small>{session.latest_safety_summary}</small><small>{session.latest_safety_at}</small></div></div>}
    {Number(session.stale)===1&&!session.ended_at&&<div className="policy-actions"><button className="danger" onClick={()=>stopStaleSession(session)}>Mark stale stopped</button></div>}
   </article>)}</div>{!sessions.length&&<p className="muted">{q.trim()?`No runtime sessions match "${q}".`:"No runtime sessions recorded yet."}</p>}</section></>
}

function problemsFilter(rows:any[],q:string){
 const needle=q.trim().toLowerCase();
 if(!needle)return rows;
 return rows.filter(row=>["display_name","character_name","action_type","status","message","summary","event_type","current_task"].some(key=>String(row?.[key]??"").toLowerCase().includes(needle)));
}

function Social(){
 const [q,setQ]=useState(""),[relationships,setRelationships]=useState<any[]>([]),[chat,setChat]=useState<any[]>([]),[proximity,setProximity]=useState<any[]>([]),[error,setError]=useState("");
 useEffect(()=>{const timer=setTimeout(()=>{api<any[]>(`/api/agents/social/relationships?q=${encodeURIComponent(q)}`).then(setRelationships).catch(x=>setError((x as Error).message));api<any[]>(`/api/agents/social/chat?q=${encodeURIComponent(q)}`).then(setChat).catch(x=>setError((x as Error).message));api<any[]>(`/api/agents/social/proximity?q=${encodeURIComponent(q)}`).then(setProximity).catch(x=>setError((x as Error).message))},160);return()=>clearTimeout(timer)},[q]);
 const companionNames=new Set(relationships.filter(row=>row.relationship_type==="COMPANION").map(row=>String(row.related_character_name||"").toLowerCase()));
 return <><article className="panel intro"><Title title="Social memory" sub="Companion targets, relationships and chat logs. FOLLOW_CHARACTER goals can seed companion relationships automatically."/></article>
  <PageToolbar query={q} onQueryChange={setQ} placeholder="Search agent, player, relationship, or message"/>
  {error&&<div className="error">{error}</div>}
  <section className="panel"><Title title="Nearby player observations" sub={`${proximity.length} recent perception snapshots. Companion targets are highlighted when visible.`}/>
   <div className="ledger-list">{proximity.map(row=>{const details=parseJson(row.details_json),players=details?.perception?.nearby?.players||[];return <article className="ledger-card social-card" key={row.id}>
    <div><strong>{row.display_name||row.agent_character_name}</strong><small>Map {details?.perception?.mapId??row.map_id??row.map} | {row.created_at}</small></div>
    {players.length?<div className="nearby-list">{players.map((player:any)=><span className={companionNames.has(String(player.name||"").toLowerCase())?"nearby-player companion":"nearby-player"} key={`${row.id}-${player.objectId}-${player.name}`}>
     <strong>{player.name||player.templateId||player.objectId}</strong><small>Lv. {player.level??"?"} | x {player.x??0}, y {player.y??0} | distanceSq {player.distanceSq??0}</small>
    </span>)}</div>:<p className="muted">No nearby players in this snapshot.</p>}
   </article>})}</div>{!proximity.length&&<p className="muted">No proximity snapshots yet. Enter an agent and run a runtime tick.</p>}</section>
  <div className="agent-detail"><section className="panel"><Title title="Relationships" sub={`${relationships.length} relationship records. COMPANION means the agent has been assigned or observed following that character.`}/>
   <div className="ledger-list">{relationships.map(row=><article className="ledger-card social-card" key={row.id}>
    <div><strong>{row.display_name||row.agent_character_name} {"->"} {row.related_character_name}</strong><small>{row.related_account_name} | {row.relationship_type}</small></div>
    <div className="ledger-grid"><Tile label="Trust" value={row.trust_score}/><Tile label="Affinity" value={row.affinity_score}/><Tile label="Updated" value={row.updated_at}/><Tile label="Notes" value={row.notes||"none"}/></div>
   </article>)}</div>{!relationships.length&&<p className="muted">No relationship records yet.</p>}</section>
   <section className="panel"><Title title="Chat logs" sub={`${chat.length} chat records.`}/>
   <div className="ledger-list">{chat.map(row=><article className="ledger-card social-card" key={row.id}>
    <div><strong>{row.display_name||row.agent_character_name}</strong><small>{row.channel_type} | {row.direction} | {row.created_at}</small></div>
    <p>{row.message}</p><small className="muted">Sender {row.sender_name||row.sender_character_id||"unknown"} | Recipient {row.recipient_name||row.recipient_character_id||"none"}</small>
   </article>)}</div>{!chat.length&&<p className="muted">No chat records yet.</p>}</section></div></>
}

function Economy(){
 const [q,setQ]=useState(""),[ledger,setLedger]=useState<any[]>([]),[error,setError]=useState("");
 useEffect(()=>{const timer=setTimeout(()=>{api<any[]>(`/api/agents/economy/ledger?q=${encodeURIComponent(q)}`).then(setLedger).catch(x=>setError((x as Error).message))},160);return()=>clearTimeout(timer)},[q]);
 const meso=ledger.reduce((sum,row)=>sum+Number(row.meso_delta||0),0);
 return <><article className="panel intro"><Title title="Economy ledger" sub="Item, meso, source and counterparty records for trading, looting, merchant and reward behavior."/></article>
  <div className="metrics compact-metrics"><article><Coins/><small>Loaded entries</small><strong>{ledger.length}</strong></article><article><Coins/><small>Net meso delta</small><strong>{meso.toLocaleString()}</strong></article></div>
  <PageToolbar query={q} onQueryChange={setQ} placeholder="Search agent, item ID, entry type, source, or counterparty"/>
  {error&&<div className="error">{error}</div>}
  <section className="panel"><Title title="Shop behavior syntax" sub="Use these in task-card parameter JSON or agent scripts. Execution still requires the Shop capability policy to be allowed."/>
   <div className="policy-grid">
    <article className="policy-card"><div><strong>Buy supplies</strong><code>{'{"shopAction":"BUY","itemId":2000000,"quantity":20}'}</code><p>Buys the matching item from the nearest visible shop NPC when the agent has enough mesos.</p></div><span className="active-state">Supported</span></article>
    <article className="policy-card"><div><strong>Sell drops</strong><code>{'{"shopAction":"SELL","itemId":4000000,"quantity":10}'}</code><p>Sells carried items through normal shop rules. Works with item IDs or item-name text.</p></div><span className="active-state">Supported</span></article>
    <article className="policy-card"><div><strong>Recharge stars or bullets</strong><code>{'{"shopAction":"RECHARGE","itemId":2070000}'}</code><p>Recharges a carried rechargeable USE item at a shop that accepts recharge.</p></div><span className="active-state">Supported</span></article>
    <article className="policy-card"><div><strong>Emergency recovery</strong><code>{'{"shopAction":"RECOVERY"}'}</code><p>Buys one affordable HP/MP recovery item from the nearest visible recovery shop candidate.</p></div><span className="active-state">Supported</span></article>
   </div>
  </section>
  <section className="panel"><Title title="Ledger entries" sub="Newest economy records first."/>
   <div className="ledger-list">{ledger.map(row=><article className="ledger-card" key={row.id}>
    <div><strong>{row.display_name||row.agent_character_name}</strong><small>{row.entry_type} | {row.created_at}</small></div>
    <span className={Number(row.meso_delta||0)>=0?"active-state":"inactive-state"}>{Number(row.meso_delta||0).toLocaleString()} meso</span>
    <div className="ledger-grid"><Tile label="Item" value={row.item_id||"none"}/><Tile label="Quantity" value={row.quantity}/><Tile label="Source" value={`${row.source_type||"none"} ${row.source_id||""}`}/><Tile label="Counterparty" value={row.counterparty_name||row.counterparty_character_id||"none"}/><Tile label="World" value={row.world??"unset"}/><Tile label="Map" value={row.map_id??"unset"}/></div>
    {row.details_json&&<details><summary>Details JSON</summary><pre>{row.details_json}</pre></details>}
   </article>)}</div>{!ledger.length&&<p className="muted">No economy ledger entries yet.</p>}</section></>
}
